class InputEmojiStatusCollectible(TLObject):
    """TL type: inputEmojiStatusCollectible"""
    CONSTRUCTOR_ID = 0x07141dbf
    SUBCLASS_OF_ID = 0xf930b138

    def __init__(self, collectible_id: int, until: Optional[datetime] = None):
        self.collectible_id = collectible_id
        self.until = until

    def to_dict(self):
        return {
            '_': 'InputEmojiStatusCollectible',
            'collectible_id': self.collectible_id,
            'until': self.until,
        }

    def _bytes(self) -> bytes:
        import io
        buf = io.BytesIO()
        buf.write(struct.pack('<I', self.CONSTRUCTOR_ID))
        flags = 0
        if self.until is not None:
            flags |= (1 << 0)
        buf.write(struct.pack('<I', flags))
        buf.write(struct.pack('<q', self.collectible_id))
        if self.until is not None:
            buf.write(TLObject.serialize_datetime(self.until))
        return buf.getvalue()

    @classmethod
    def from_reader(cls, reader):
        _args = {}
        flags = reader.read_int(signed=False)
        _val_collectible_id = reader.read_long()
        _args['collectible_id'] = _val_collectible_id
        if flags & (1 << 0):
            _val_until = reader.tgread_date()
            _args['until'] = _val_until
        else:
            _args['until'] = None
        return cls(**_args)


