class InputGeoPoint(TLObject):
    """TL type: inputGeoPoint"""
    CONSTRUCTOR_ID = 0x48222faf
    SUBCLASS_OF_ID = 0x0430d225

    def __init__(self, lat: float, long: float, accuracy_radius: Optional[int] = None):
        self.lat = lat
        self.long = long
        self.accuracy_radius = accuracy_radius

    def to_dict(self):
        return {
            '_': 'InputGeoPoint',
            'lat': self.lat,
            'long': self.long,
            'accuracy_radius': self.accuracy_radius,
        }

    def _bytes(self) -> bytes:
        import io
        buf = io.BytesIO()
        buf.write(struct.pack('<I', self.CONSTRUCTOR_ID))
        flags = 0
        if self.accuracy_radius is not None:
            flags |= (1 << 0)
        buf.write(struct.pack('<I', flags))
        buf.write(struct.pack('<d', self.lat))
        buf.write(struct.pack('<d', self.long))
        if self.accuracy_radius is not None:
            buf.write(struct.pack('<i', self.accuracy_radius))
        return buf.getvalue()

    @classmethod
    def from_reader(cls, reader):
        _args = {}
        flags = reader.read_int(signed=False)
        _val_lat = reader.read_double()
        _args['lat'] = _val_lat
        _val_long = reader.read_double()
        _args['long'] = _val_long
        if flags & (1 << 0):
            _val_accuracy_radius = reader.read_int()
            _args['accuracy_radius'] = _val_accuracy_radius
        else:
            _args['accuracy_radius'] = None
        return cls(**_args)


