class ShippingOption(TLObject):
    """TL type: shippingOption"""
    CONSTRUCTOR_ID = 0xb6213cdf
    SUBCLASS_OF_ID = 0xf4e94c78

    def __init__(self, id: str, title: str, prices: List['TypeLabeledPrice']):
        self.id = id
        self.title = title
        self.prices = prices

    def to_dict(self):
        return {
            '_': 'ShippingOption',
            'id': self.id,
            'title': self.title,
            'prices': self.prices,
        }

    def _bytes(self) -> bytes:
        import io
        buf = io.BytesIO()
        buf.write(struct.pack('<I', self.CONSTRUCTOR_ID))
        buf.write(TLObject.serialize_bytes(self.id))
        buf.write(TLObject.serialize_bytes(self.title))
        buf.write(struct.pack('<i', 0x1cb5c415))  # vector id
        buf.write(struct.pack('<i', len(self.prices)))
        for item in self.prices:
            buf.write(bytes(item))
        return buf.getvalue()

    @classmethod
    def from_reader(cls, reader):
        _args = {}
        _val_id = reader.tgread_string()
        _args['id'] = _val_id
        _val_title = reader.tgread_string()
        _args['title'] = _val_title
        _vec_id = reader.read_int(signed=False)
        if _vec_id != 0x1cb5c415:
            raise RuntimeError(f'Expected vector but got 0x{_vec_id:08x}')
        _count_prices = reader.read_int(signed=False)  # BUG6 fix: unsigned count
        _list_prices = []
        for _ in range(_count_prices):
            _item_prices = reader.tgread_object()
            _list_prices.append(_item_prices)
        _args['prices'] = _list_prices
