    def __init__(self, stars: int, yearly_boosts: int, currency: str, amount: int, winners: List['TypeStarsGiveawayWinnersOption'], extended: Optional[bool] = None, default: Optional[bool] = None, store_product: Optional[str] = None):
        self.stars = stars
        self.yearly_boosts = yearly_boosts
        self.currency = currency
        self.amount = amount
        self.winners = winners
        self.extended = extended
        self.default = default
        self.store_product = store_product

    def to_dict(self):
        return {
            '_': 'StarsGiveawayOption',
            'stars': self.stars,
            'yearly_boosts': self.yearly_boosts,
            'currency': self.currency,
            'amount': self.amount,
            'winners': self.winners,
            'extended': self.extended,
            'default': self.default,
            'store_product': self.store_product,
        }

    def _bytes(self) -> bytes:
        import io
        buf = io.BytesIO()
        buf.write(struct.pack('<I', self.CONSTRUCTOR_ID))
        flags = 0
        if self.extended:
            flags |= (1 << 0)
        if self.default:
            flags |= (1 << 1)
        if self.store_product is not None:
            flags |= (1 << 2)
        buf.write(struct.pack('<I', flags))
        buf.write(struct.pack('<q', self.stars))
        buf.write(struct.pack('<i', self.yearly_boosts))
        if self.store_product is not None:
            buf.write(TLObject.serialize_bytes(self.store_product))
        buf.write(TLObject.serialize_bytes(self.currency))
        buf.write(struct.pack('<q', self.amount))
        buf.write(struct.pack('<i', 0x1cb5c415))  # vector id
        buf.write(struct.pack('<i', len(self.winners)))
        for item in self.winners:
            buf.write(bytes(item))
        return buf.getvalue()

    @classmethod
    def from_reader(cls, reader):
        _args = {}
        flags = reader.read_int(signed=False)
        _args['extended'] = bool(flags & (1 << 0))
        _args['default'] = bool(flags & (1 << 1))
        _val_stars = reader.read_long()
        _args['stars'] = _val_stars
        _val_yearly_boosts = reader.read_int()
        _args['yearly_boosts'] = _val_yearly_boosts
        if flags & (1 << 2):
            _val_store_product = reader.tgread_string()
            _args['store_product'] = _val_store_product
        else:
            _args['store_product'] = None
        _val_currency = reader.tgread_string()
        _args['currency'] = _val_currency
        _val_amount = reader.read_long()
        _args['amount'] = _val_amount
        _vec_id = reader.read_int(signed=False)
        if _vec_id != 0x1cb5c415:
            raise RuntimeError(f'Expected vector but got 0x{_vec_id:08x}')
        _count_winners = reader.read_int(signed=False)  # BUG6 fix: unsigned count
        _list_winners = []
        for _ in range(_count_winners):
            _item_winners = reader.tgread_object()
            _list_winners.append(_item_winners)
        _args['winners'] = _list_winners
        return cls(**_args)


